%[text] ## Numbers of customers reneged
%%

%%
%[text] ## Numbers of customers reneged
%%
classes = cellfun(@class, QSamples, 'UniformOutput', false) %[output:43393b98]
%%
RenegedCounts = cellfun(@(q) length(q.Reneged) / (length(q.Reneged) + length(q.Served)), QSamples);
meanRenegedFraction = mean(RenegedCounts);
fprintf('Average fraction of customers lost to reneging: %.4f\n', meanRenegedFraction); %[output:69804b7a]





NumReneged = cellfun(@(q) length(q.Reneged), QSamples);

fig = figure(); %[output:84cc986d]
ax = axes(fig); %[output:84cc986d]

histogram(ax, NumReneged, ... %[output:84cc986d]
    Normalization="probability", ... %[output:84cc986d]
    BinMethod="integers"); %[output:84cc986d]

hold(ax, "on"); %[output:84cc986d]

nMax = max(NumReneged);
n = 0:nMax;

counts = histcounts(NumReneged, ...
    'BinMethod','integers', ...
    'Normalization','probability');

plot(ax, n, counts(1:length(n)), 'o', ... %[output:84cc986d]
    MarkerEdgeColor='k', ... %[output:84cc986d]
    MarkerFaceColor='r'); %[output:84cc986d]

xlabel('n (number reneged)'); %[output:84cc986d]
ylabel('Probability'); %[output:84cc986d]
legend('Simulation', 'Overlay'); %[output:84cc986d]
title('P_n empirical vs theoretical results'); %[output:84cc986d]


